 1→#!/usr/bin/env node
 2→// CJS bootstrap: re-launches with tsx ESM support, then runs the TS entry point.
 3→// Preserves `node backend/server.cjs` interface for dev.sh and Electron main process.
 4→const { spawn } = require('child_process');
 5→const path = require('path');
 6→const { pathToFileURL } = require('url');
 7→
 8→// Resolve tsx/esm absolutely so the bootstrap works regardless of CWD
 9→const tsxEsm = pathToFileURL(require.resolve('tsx/esm')).href;
10→
11→const child = spawn(
12→  process.execPath,
13→  ['--import', tsxEsm, path.join(__dirname, 'src/server.ts')],
14→  {
15→    stdio: 'inherit',
16→    env: {
17→      ...process.env,
18→      // Point tsx at the backend tsconfig so @shared/* path aliases resolve
19→      TSX_TSCONFIG_PATH: path.join(__dirname, 'tsconfig.json'),
20→    },
21→  }
22→);
23→
24→child.on('error', (err) => {
25→  console.error('[BOOTSTRAP] Failed to start backend:', err.message);
26→  process.exit(1);
27→});
28→
29→child.on('exit', (code, signal) => {
30→  if (signal) {
31→    // Remove custom handlers so re-raise hits the default (terminate)
32→    process.removeAllListeners('SIGINT');
33→    process.removeAllListeners('SIGTERM');
34→    process.kill(process.pid, signal);
35→    return;
36→  }
37→  process.exit(code ?? 1);
38→});
39→
40→process.on('SIGINT', () => {
41→  if (!child.killed) child.kill('SIGINT');
42→});
43→process.on('SIGTERM', () => {
44→  if (!child.killed) child.kill('SIGTERM');
45→});
46→

// apps/backend/build.ts
// esbuild script to bundle the backend into a single CJS file for production.
// Run: bunx tsx apps/backend/build.ts

import { build } from "esbuild";
import * as path from "path";
import { fileURLToPath } from "url";

const backendDir = path.dirname(fileURLToPath(import.meta.url));

build({
  entryPoints: [path.join(backendDir, "src/server.ts")],
  bundle: true,
  platform: "node",
  target: "node22",
  format: "cjs",
  outfile: path.join(backendDir, "dist/server.bundled.cjs"),
  external: [
    // Native modules — must be resolved at runtime
    "better-sqlite3",
    "node-pty",
    // WebSocket library with optional native extensions
    "ws",
    // Sentry — optional, loaded at runtime if DSN is configured
    "@sentry/node",
  ],
  // Mark all Node.js built-ins as external
  packages: "external",
  minify: false,
  sourcemap: false,
  logLevel: "info",
  // Resolve @shared/* path alias
  alias: {
    "@shared": path.join(backendDir, "../../shared"),
  },
})
  .then(() => {
    console.log("Backend build complete!");
  })
  .catch((error) => {
    console.error("Backend build failed:", error);
    process.exit(1);
  });

  1→import * as Sentry from "@sentry/node";
  2→import { serve } from "@hono/node-server";
  3→import { createApp } from "./app";
  4→import { initDatabase, closeDatabase, DB_PATH } from "./lib/database";
  5→import { closeAll as closeAllWsConnections } from "./services/ws.service";
  6→import { ensureRelayConnected, disconnectFromRelay } from "./services/relay.service";
  7→import { getSetting } from "./services/settings.service";
  8→import * as agentService from "./services/agent";
  9→import { destroyAllPtySessions } from "./services/pty.service";
 10→import { destroyAllWatchers } from "./services/fs-watcher.service";
 11→import { setApp } from "./services/route-delegate";
 12→import { invalidate } from "./services/query-engine";
 13→
 14→// Initialize Sentry before anything else.
 15→// DSN passed as env var from Electron main process (not hardcoded — open source repo).
 16→if (process.env.SENTRY_DSN) {
 17→  Sentry.init({
 18→    dsn: process.env.SENTRY_DSN,
 19→    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 20→    sendDefaultPii: false,
 21→    initialScope: { tags: { process: "backend" } },
 22→  });
 23→}
 24→
 25→/**
 26→ * OpenDevs Backend Server
 27→ *
 28→ * Handles workspace CRUD, sessions, repos, config, and stats.
 29→ * Agent runtime (Claude SDK) is managed by the agent-server (sidecar).
 30→ */
 31→
 32→// Initialize database
 33→const db = initDatabase();
 34→
 35→// Backfill git_origin_url for repos added before we tracked origin URLs.
 36→// Runs once at startup (fire-and-forget) so WS subscribers get the data
 37→// on their first snapshot instead of waiting for GET /repos.
 38→async function backfillGitOriginUrls(): Promise<void> {
 39→  const { execFile } = await import("child_process");
 40→  const { promisify } = await import("util");
 41→  const execFileAsync = promisify(execFile);
 42→
 43→  try {
 44→    const nullUrlRepos = db
 45→      .prepare("SELECT id, root_path FROM repositories WHERE git_origin_url IS NULL")
 46→      .all() as { id: string; root_path: string }[];
 47→    if (nullUrlRepos.length === 0) return;
 48→
 49→    let updated = 0;
 50→    // Process in batches of 5 to cap concurrent git subprocesses
 51→    const BATCH_SIZE = 5;
 52→    for (let i = 0; i < nullUrlRepos.length; i += BATCH_SIZE) {
 53→      const batch = nullUrlRepos.slice(i, i + BATCH_SIZE);
 54→      const results = await Promise.allSettled(
 55→        batch.map(async (repo) => {
 56→          const { stdout } = await execFileAsync("git", ["remote", "get-url", "origin"], {
 57→            cwd: repo.root_path,
 58→            encoding: "utf-8",
 59→            timeout: 2000,
 60→          });
 61→          const url = stdout.trim();
 62→          if (url) {
 63→            db.prepare("UPDATE repositories SET git_origin_url = ? WHERE id = ?").run(url, repo.id);
 64→            return true;
 65→          }
 66→          return false;
 67→        })
 68→      );
 69→      updated += results.filter((r) => r.status === "fulfilled" && r.value).length;
 70→    }
 71→
 72→    // Push fresh data to WS subscribers so sidebar shows GitHub icons immediately
 73→    if (updated > 0) {
 74→      invalidate(["workspaces"]);
 75→    }
 76→  } catch {
 77→    // Backfill failed — not critical, icons will appear after next workspace creation
 78→  }
 79→}
 80→void backfillGitOriginUrls();
 81→
 82→// Create Hono app + WebSocket injector
 83→const { app, injectWebSocket } = createApp();
 84→
 85→// Register the Hono app for in-process route delegation (q:request/q:mutate → Hono routes)
 86→setApp(app);
 87→
 88→// Global variable to store actual port (used by health endpoint)
 89→let actualServerPort: number | null = null;
 90→
 91→export function getServerPort() {
 92→  return actualServerPort;
 93→}
 94→
 95→// Start server with dynamic port allocation
 96→const PORT = process.env.PORT ? parseInt(process.env.PORT) : 0;
 97→
 98→// Bind 0.0.0.0 to accept connections from all interfaces.
 99→// Remote access is gated by remoteGateMiddleware (rejects non-localhost when disabled).
100→const server = serve(
101→  {
102→    fetch: app.fetch,
103→    port: PORT,
104→    hostname: "0.0.0.0",
105→  },
106→  (info) => {
107→    actualServerPort = info.port;
108→
109→    // CRITICAL: Machine-readable port output for Electron main process and dev.sh
110→    console.log(`[BACKEND_PORT]${info.port}`);
111→
112→    console.log("\nOpenDevs Backend Server");
113→    console.log(`API Server: http://0.0.0.0:${info.port}`);
114→    console.log(`Database: ${DB_PATH}`);
115→    console.log("Server ready!\n");
116→  }
117→);
118→
119→// Inject WebSocket support into the HTTP server
120→injectWebSocket(server);
121→
122→const remoteEnabled = getSetting("remote_access_enabled");
123→if (remoteEnabled === true) {
124→  ensureRelayConnected();
125→}
126→
127→// Connect to agent-server (sidecar).
128→//
129→// Two bootstrap paths:
130→// 1. AGENT_SERVER_URL is set (dev.sh): sidecar already running, connect directly.
131→// 2. SIDECAR_BUNDLE_PATH is set (Electron): spawn sidecar as child process,
132→//    parse LISTEN_URL from its stdout, then connect.
133→const agentServerUrl = process.env.AGENT_SERVER_URL;
134→const sidecarBundlePath = process.env.SIDECAR_BUNDLE_PATH;
135→
136→if (agentServerUrl) {
137→  // Path 1: Direct connection (dev.sh spawned the sidecar externally)
138→  agentService.init(agentServerUrl);
139→} else if (sidecarBundlePath) {
140→  // Path 2: Spawn sidecar and connect (Electron desktop mode)
141→  void spawnSidecarAndConnect(sidecarBundlePath);
142→}
143→
144→// Track sidecar child process for cleanup on shutdown
145→let sidecarChild: import("child_process").ChildProcess | null = null;
146→
147→function killSidecar(): void {
148→  if (sidecarChild && !sidecarChild.killed) {
149→    sidecarChild.kill("SIGTERM");
150→    sidecarChild = null;
151→  }
152→}
153→
154→/** Spawn the sidecar bundle as a child process and connect to its WebSocket. */
155→async function spawnSidecarAndConnect(bundlePath: string): Promise<void> {
156→  const { spawn } = await import("child_process");
157→  const fs = await import("fs");
158→
159→  if (!fs.existsSync(bundlePath)) {
160→    console.error(`[server] Sidecar bundle not found: ${bundlePath}`);
161→    return;
162→  }
163→
164→  sidecarChild = spawn(process.execPath, [bundlePath], {
165→    stdio: ["ignore", "pipe", "pipe"],
166→    env: {
167→      ...process.env,
168→      // Forward database path so sidecar can pass it to agents
169→      DATABASE_PATH: process.env.DATABASE_PATH,
170→      // Forward notebook server path
171→      NOTEBOOK_SERVER_BUNDLE_PATH: process.env.NOTEBOOK_SERVER_BUNDLE_PATH,
172→    },
173→  });
174→
175→  const sidecar = sidecarChild!;
176→  let stdoutBuffer = "";
177→
178→  sidecar.stdout?.on("data", (data: Buffer) => {
179→    stdoutBuffer += data.toString();
180→    const lines = stdoutBuffer.split("\n");
181→    stdoutBuffer = lines.pop() ?? "";
182→
183→    for (const line of lines) {
184→      const trimmed = line.trim();
185→      if (!trimmed) continue;
186→      console.log("[sidecar]", trimmed);
187→
188→      // Capture the LISTEN_URL and connect
189→      if (trimmed.startsWith("LISTEN_URL=")) {
190→        const url = trimmed.slice("LISTEN_URL=".length);
191→        console.log(`[server] Sidecar spawned and listening at ${url}`);
192→        agentService.init(url);
193→      }
194→    }
195→  });
196→
197→  sidecar.stderr?.on("data", (data: Buffer) => {
198→    for (const line of data.toString().split("\n")) {
199→      if (line.trim()) console.error("[sidecar:stderr]", line.trim());
200→    }
201→  });
202→
203→  sidecar.on("exit", (code, signal) => {
204→    console.log(`[sidecar] Exited with code=${code} signal=${signal}`);
205→    sidecarChild = null;
206→  });
207→}
208→
209→// Global error handlers
210→process.on("uncaughtException", (error, origin) => {
211→  console.error("[FATAL] Uncaught Exception:", origin, error);
212→  Sentry.captureException(error);
213→  Sentry.close(2000).finally(() => {
214→    destroyAllPtySessions();
215→    destroyAllWatchers();
216→    killSidecar();
217→    try {
218→      closeDatabase();
219→    } catch {}
220→    process.exit(1);
221→  });
222→});
223→
224→process.on("unhandledRejection", (reason) => {
225→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
226→  // rejection reasons automatically. We only log here for local visibility.
227→  console.error("[FATAL] Unhandled Promise Rejection:", reason);
228→});
229→
230→// Graceful shutdown
231→function shutdown() {
232→  console.log("\nShutting down...");
233→  agentService.shutdown();
234→  destroyAllPtySessions();
235→  destroyAllWatchers();
236→  killSidecar();
237→  disconnectFromRelay();
238→  closeAllWsConnections();
239→  closeDatabase();
240→  process.exit(0);
241→}
242→
243→process.on("SIGINT", shutdown);
244→process.on("SIGTERM", shutdown);
245→

  1→import { Hono } from "hono";
  2→import { cors } from "hono/cors";
  3→import { createNodeWebSocket } from "@hono/node-ws";
  4→import { errorHandler } from "./middleware/error-handler";
  5→import { remoteGateMiddleware } from "./middleware/remote-gate";
  6→import { authMiddleware } from "./middleware/remote-auth";
  7→import { validateDeviceToken } from "./services/remote-auth.service";
  8→import { addConnection, removeConnection, handleProtocolMessage } from "./services/ws.service";
  9→import { removeSubs as removeQuerySubs } from "./services/query-engine";
 10→import { getRelayStatus } from "./services/relay.service";
 11→import { isLocalhost, getClientIp } from "./lib/network";
 12→import healthRoutes from "./routes/health";
 13→import workspaceRoutes from "./routes/workspaces";
 14→import workspaceDiffRoutes from "./routes/workspaces.diff";
 15→import workspacePrRoutes from "./routes/workspaces.pr";
 16→import workspaceDesignRoutes from "./routes/workspaces.design";
 17→import sessionRoutes from "./routes/sessions";
 18→import repoRoutes from "./routes/repos";
 19→import agentConfigRoutes from "./routes/agent-config";
 20→import settingsRoutes from "./routes/settings";
 21→import statsRoutes from "./routes/stats";
 22→import onboardingRoutes from "./routes/onboarding";
 23→import authRoutes from "./routes/remote-auth";
 24→import filesRoutes from "./routes/files";
 25→// Legacy sidecar HTTP relay routes removed — all agent communication
 26→// now goes through WebSocket AgentClient (services/agent/client.ts)
 27→
 28→export function createApp() {
 29→  const app = new Hono();
 30→  const { upgradeWebSocket, injectWebSocket } = createNodeWebSocket({ app });
 31→
 32→  // Middleware — order matters:
 33→  // 1. Remote gate rejects non-localhost when remote access is disabled
 34→  // 2. CORS headers for browser requests
 35→  // 3. Auth validates Bearer tokens for remote clients (localhost exempt)
 36→  app.use("*", remoteGateMiddleware);
 37→  app.use("*", cors());
 38→  app.use("/api/*", authMiddleware);
 39→
 40→  // Mount route groups
 41→  app.route("/api", healthRoutes);
 42→  app.route("/api", authRoutes);
 43→  app.route("/api", workspaceRoutes);
 44→  app.route("/api", workspaceDiffRoutes);
 45→  app.route("/api", workspacePrRoutes);
 46→  app.route("/api", workspaceDesignRoutes);
 47→  app.route("/api", sessionRoutes);
 48→  app.route("/api", repoRoutes);
 49→  app.route("/api", agentConfigRoutes);
 50→  app.route("/api", settingsRoutes);
 51→  app.route("/api", statsRoutes);
 52→  app.route("/api", filesRoutes);
 53→  // Legacy sidecar HTTP routes removed (replaced by WS AgentClient)
 54→  app.route("/api", onboardingRoutes);
 55→
 56→  // Relay status endpoint
 57→  app.get("/api/relay/status", (c) => {
 58→    return c.json(getRelayStatus());
 59→  });
 60→
 61→  // WebSocket route for remote access.
 62→  // Localhost connections are auto-authenticated. Remote clients must send
 63→  // { type: "initialize", token: "..." } as their first message.
 64→  app.get(
 65→    "/ws",
 66→    upgradeWebSocket((c) => {
 67→      const ip = getClientIp(c);
 68→      const isLocal = isLocalhost(ip);
 69→      let connectionId: string | null = null;
 70→
 71→      return {
 72→        onOpen(_evt, ws) {
 73→          if (isLocal) {
 74→            // Desktop/localhost connections skip token auth
 75→            connectionId = addConnection(ws, null);
 76→            ws.send(JSON.stringify({ type: "connected", connectionId }));
 77→          }
 78→          // Remote clients stay unauthenticated until initialize message
 79→        },
 80→
 81→        onMessage(evt, ws) {
 82→          let msg: Record<string, unknown>;
 83→          try {
 84→            const raw = typeof evt.data === "string" ? evt.data : String(evt.data);
 85→            msg = JSON.parse(raw);
 86→          } catch {
 87→            return; // Ignore malformed messages
 88→          }
 89→
 90→          // Unauthenticated remote client — must initialize first
 91→          if (!connectionId) {
 92→            if (msg.type === "initialize" && typeof msg.token === "string") {
 93→              const device = validateDeviceToken(msg.token);
 94→              if (device) {
 95→                connectionId = addConnection(ws, device.id);
 96→                ws.send(JSON.stringify({ type: "connected", connectionId }));
 97→              } else {
 98→                ws.send(JSON.stringify({ type: "error", message: "Invalid token" }));
 99→                ws.close(4001, "Invalid token");
100→              }
101→            } else {
102→              ws.send(
103→                JSON.stringify({ type: "error", message: "Must send initialize with token" })
104→              );
105→              ws.close(4001, "Not authenticated");
106→            }
107→            return;
108→          }
109→
110→          // Authenticated — handle protocol messages (shared with relay virtual connections)
111→          handleProtocolMessage(connectionId, msg);
112→        },
113→
114→        onClose() {
115→          if (connectionId) {
116→            removeQuerySubs(connectionId);
117→            removeConnection(connectionId);
118→            connectionId = null;
119→          }
120→        },
121→      };
122→    })
123→  );
124→
125→  // Centralized error handling
126→  app.onError(errorHandler);
127→
128→  return { app, injectWebSocket };
129→}
130→

 1→import * as Sentry from "@sentry/react";
 2→import React from "react";
 3→import ReactDOM from "react-dom/client";
 4→import { PostHogProvider } from "posthog-js/react";
 5→import App from "./App";
 6→import "../global.css";
 7→import { reportError } from "@/shared/utils/errorReporting";
 8→
 9→// Initialize Sentry before anything else.
10→// DSN is injected at build time via VITE_SENTRY_DSN env var (not hardcoded — open source repo).
11→const sentryDsn = import.meta.env.VITE_SENTRY_DSN;
12→if (sentryDsn) {
13→  Sentry.init({
14→    dsn: sentryDsn,
15→    environment: import.meta.env.DEV ? "development" : "production",
16→    release: `opendevs@${__APP_VERSION__}`,
17→    sendDefaultPii: true,
18→    enabled: !import.meta.env.DEV,
19→  });
20→}
21→
22→// Ensure Electron class is applied (backup check - preload may not have run yet)
23→if ((window as any).electronAPI) {
24→  document.documentElement.classList.add("electron");
25→}
26→
27→// Window focus/blur tracking — toggles .window-inactive for vibrancy dimming
28→window.addEventListener("focus", () =>
29→  document.documentElement.classList.remove("window-inactive")
30→);
31→window.addEventListener("blur", () => document.documentElement.classList.add("window-inactive"));
32→
33→const w = window as Window & { __opendevsErrorHandlers__?: boolean };
34→if (!w.__opendevsErrorHandlers__) {
35→  w.__opendevsErrorHandlers__ = true;
36→
37→  window.addEventListener("error", (event) => {
38→    reportError(event.error ?? event.message, {
39→      source: "window.error",
40→      extra: {
41→        filename: event.filename,
42→        lineno: event.lineno,
43→        colno: event.colno,
44→      },
45→    });
46→  });
47→
48→  window.addEventListener("unhandledrejection", (event) => {
49→    reportError(event.reason, { source: "window.unhandledrejection" });
50→  });
51→}
52→
53→const posthogOptions = {
54→  api_host: import.meta.env.VITE_PUBLIC_POSTHOG_HOST,
55→  defaults: "2026-01-30",
56→  opt_out_capturing_by_default: false,
57→  autocapture: false,
58→  capture_pageview: false,
59→  capture_pageleave: false,
60→  disable_session_recording: true,
61→  persistence: "localStorage" as const,
62→} as const;
63→
64→ReactDOM.createRoot(document.getElementById("root") as HTMLElement).render(
65→  <React.StrictMode>
66→    <PostHogProvider
67→      apiKey={import.meta.env.VITE_PUBLIC_POSTHOG_KEY ?? ""}
68→      options={posthogOptions}
69→    >
70→      <App />
71→    </PostHogProvider>
72→  </React.StrictMode>
73→);
74→

 1→/// <reference types="vite/client" />
 2→/// <reference types="vite-plugin-svgr/client" />
 3→
 4→/** App version injected by Vite's `define` from package.json */
 5→declare const __APP_VERSION__: string;
 6→
 7→interface ImportMetaEnv {
 8→  readonly VITE_BACKEND_PORT?: string;
 9→
10→  readonly VITE_SENTRY_DSN?: string;
11→  readonly VITE_PUBLIC_POSTHOG_HOST?: string;
12→  readonly VITE_PUBLIC_POSTHOG_KEY?: string;
13→}
14→
15→interface ImportMeta {
16→  readonly env: ImportMetaEnv;
17→}
18→
19→/** Compiled JS files imported as raw strings (browser inject scripts) */
20→declare module "*.js?raw" {
21→  const content: string;
22→  export default content;
23→}
24→
25→/**
26→ * Electron preload bridge — available when running inside Electron.
27→ * Undefined in browser mode. The full typed API is defined in
28→ * apps/desktop/preload/index.ts and exposed via contextBridge.
29→ */
30→interface Window {
31→  electronAPI?: {
32→    getBackendPort: () => Promise<number>;
33→    getAuthToken: () => Promise<string>;
34→    isFullscreen: () => Promise<boolean>;
35→    onFullscreenChange: (callback: (payload: { isFullscreen: boolean }) => void) => () => void;
36→    getAppVersion: () => Promise<string>;
37→    checkForUpdates: () => Promise<unknown>;
38→    downloadUpdate: () => Promise<void>;
39→    installUpdate: () => Promise<void>;
40→    onUpdateState: (callback: (state: unknown) => void) => () => void;
41→    on: (event: string, callback: (...args: unknown[]) => void) => () => void;
42→    invoke: (channel: string, args?: unknown) => Promise<unknown>;
43→    send: (channel: string, ...args: unknown[]) => void;
44→  };
45→}
46→

  1→/**
  2→ * WebSocket Query Protocol Client
  3→ *
  4→ * Singleton client that connects to the backend's /ws endpoint and handles
  5→ * the q:* protocol for real-time data subscriptions, one-shot requests,
  6→ * mutations, and async commands.
  7→ *
  8→ * Protocol:
  9→ *   Client sends: q:subscribe, q:unsubscribe, q:request, q:mutate, q:command
 10→ *   Server sends: q:snapshot, q:delta, q:response, q:mutate_result, q:command_ack, q:error, q:event, ping
 11→ *   Client responds to ping with pong
 12→ *
 13→ * Relay mode (web-production):
 14→ *   Connects through cloud relay at wss://relay.rundeus.com/api/servers/{id}/connect
 15→ *   Sends { type: "authenticate", token } on open for device token auth.
 16→ *   Handles relay control frames: authenticated, auth_failed, server_reconnecting, server_connected.
 17→ *
 18→ * On reconnect, all active subscriptions are re-established automatically.
 19→ */
 20→
 21→import { match } from "ts-pattern";
 22→import { resolveBackendEndpoints, isRelayMode } from "@/shared/config/backend.config";
 23→import { getStoredToken, signOut } from "@/features/auth";
 24→import type { QueryResource, CommandName } from "@shared/types/query-protocol";
 25→
 26→// ---- Types ----
 27→
 28→type SnapshotCallback = (data: unknown) => void;
 29→type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
 30→type EventCallback = (event: string, data: unknown) => void;
 31→
 32→interface PendingCommand {
 33→  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
 34→  reject: (err: Error) => void;
 35→}
 36→
 37→interface PendingRequest {
 38→  resolve: (data: unknown) => void;
 39→  reject: (err: Error) => void;
 40→  timer: ReturnType<typeof setTimeout>;
 41→}
 42→
 43→interface PendingMutation {
 44→  resolve: (result: { success: boolean; data?: unknown; error?: string }) => void;
 45→  reject: (err: Error) => void;
 46→  timer: ReturnType<typeof setTimeout>;
 47→}
 48→
 49→interface Subscription {
 50→  id: string;
 51→  resource: QueryResource;
 52→  params?: Record<string, unknown>;
 53→  onSnapshot: SnapshotCallback;
 54→  onDelta?: DeltaCallback;
 55→}
 56→
 57→// ---- Reconnect Config ----
 58→
 59→const BACKOFF_BASE_MS = 500;
 60→const BACKOFF_MAX_MS = 8000;
 61→
 62→// ---- Singleton State ----
 63→
 64→let ws: WebSocket | null = null;
 65→let _connectionId: string | null = null;
 66→let connected = false;
 67→let connecting = false;
 68→let reconnectAttempt = 0;
 69→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 70→let subCounter = 0;
 71→
 72→/** Active subscriptions keyed by client-assigned ID. */
 73→const subscriptions = new Map<string, Subscription>();
 74→
 75→/** Pending commands waiting for q:command_ack. */
 76→const pendingCommands = new Map<string, PendingCommand>();
 77→
 78→/** Pending one-shot q:request frames waiting for q:response. */
 79→const pendingRequests = new Map<string, PendingRequest>();
 80→
 81→/** Pending q:mutate frames waiting for q:mutate_result. */
 82→const pendingMutations = new Map<string, PendingMutation>();
 83→
 84→/** Listeners for q:event broadcasts. */
 85→const eventListeners = new Set<EventCallback>();
 86→
 87→/** Listeners notified when connection state changes (connected/disconnected). */
 88→const connectionChangeListeners = new Set<(connected: boolean) => void>();
 89→
 90→/** Counter for generating unique command frame IDs. */
 91→let commandCounter = 0;
 92→
 93→/** Counter for generating unique request/mutation frame IDs. */
 94→let requestCounter = 0;
 95→
 96→/** Resolvers waiting for the initial "connected" frame after open. */
 97→let connectResolve: (() => void) | null = null;
 98→let connectReject: ((err: Error) => void) | null = null;
 99→
100→// ---- Public API ----
101→
102→/** Generate a unique subscription ID. */
103→function nextSubId(): string {
104→  return `sub_${++subCounter}`;
105→}
106→
107→/**
108→ * Connect to the backend WebSocket. Resolves once authenticated.
109→ * No-op if already connected or connecting.
110→ *
111→ * In relay mode, pass the serverId so the WS URL can be resolved.
112→ */
113→export async function connect(serverId?: string): Promise<void> {
114→  if (connected) return;
115→  if (connecting) {
116→    // Wait for the in-flight connection attempt
117→    return new Promise<void>((resolve, reject) => {
118→      const prevResolve = connectResolve;
119→      const prevReject = connectReject;
120→      connectResolve = () => {
121→        prevResolve?.();
122→        resolve();
123→      };
124→      connectReject = (err) => {
125→        prevReject?.(err);
126→        reject(err);
127→      };
128→    });
129→  }
130→
131→  connecting = true;
132→
133→  return new Promise<void>((resolve, reject) => {
134→    connectResolve = resolve;
135→    connectReject = reject;
136→    openSocket(serverId).catch((err) => {
137→      connecting = false;
138→      connectReject?.(err);
139→      connectResolve = null;
140→      connectReject = null;
141→    });
142→  });
143→}
