145→/**
146→ * Subscribe to a query resource. Returns an unsubscribe function.
147→ *
148→ * On subscription, the server sends an initial q:snapshot. Subsequent
149→ * invalidations push q:snapshot (full replace) or q:delta (incremental).
150→ */
151→export function subscribe(
152→  resource: QueryResource,
153→  params: Record<string, unknown> | undefined,
154→  onSnapshot: SnapshotCallback,
155→  onDelta?: DeltaCallback
156→): () => void {
157→  const id = nextSubId();
158→  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
159→  subscriptions.set(id, sub);
160→
161→  // If connected, send subscribe frame immediately
162→  if (connected && ws) {
163→    sendFrame({
164→      type: "q:subscribe",
165→      id,
166→      resource,
167→      ...(params ? { params } : {}),
168→    });
169→  }
170→
171→  // Return unsubscribe function
172→  return () => {
173→    subscriptions.delete(id);
174→    if (connected && ws) {
175→      sendFrame({ type: "q:unsubscribe", id });
176→    }
177→  };
178→}
